const tables = $('Query Table Sizes').all().map(i => i.json);
const slowQueries = $('Query Slow Queries').all().map(i => i.json);

const issues = [];

// Check for large tables (> 1GB)
const largeTables = tables.filter(t => t.size_bytes > 1073741824);
if (largeTables.length > 0) {
  issues.push({
    type: 'LARGE_TABLE',
    severity: 'warning',
    details: largeTables.map(t => `${t.tablename}: ${t.total_size}`)
  });
}

// Check for high dead row percentage (> 20%)
const bloatedTables = tables.filter(t => parseFloat(t.dead_pct || 0) > 20);
if (bloatedTables.length > 0) {
  issues.push({
    type: 'TABLE_BLOAT',
    severity: 'warning',
    details: bloatedTables.map(t => `${t.tablename}: ${t.dead_pct}% dead rows (${t.dead_rows} dead / ${t.live_rows} live)`)
  });
}

// Check for tables not vacuumed recently (> 7 days)
const staleVacuum = tables.filter(t => {
  if (!t.last_autovacuum && !t.last_vacuum) return true;
  const lastVac = new Date(t.last_autovacuum || t.last_vacuum);
  return (Date.now() - lastVac.getTime()) > 7 * 24 * 60 * 60 * 1000;
});
if (staleVacuum.length > 0) {
  issues.push({
    type: 'STALE_VACUUM',
    severity: 'info',
    details: staleVacuum.map(t => `${t.tablename}: last vacuum ${t.last_autovacuum || t.last_vacuum || 'never'}`)
  });
}

// Slow queries
if (slowQueries.length > 0) {
  issues.push({
    type: 'SLOW_QUERIES',
    severity: 'critical',
    details: slowQueries.map(q => `PID ${q.pid}: ${q.duration} — ${(q.query || '').substring(0, 100)}...`)
  });
}

// Total DB size
const totalBytes = tables.reduce((sum, t) => sum + (t.size_bytes || 0), 0);
const totalSizeGB = (totalBytes / 1073741824).toFixed(2);

return [{
  json: {
    issues,
    hasIssues: issues.length > 0,
    totalSizeGB,
    tableCount: tables.length,
    slowQueryCount: slowQueries.length,
    tables: tables.slice(0, 5).map(t => ({ name: t.tablename, size: t.total_size, rows: t.live_rows }))
  }
}];

const data = $input.first().json;

let message = `DATABASE HEALTH ALERT\n`;
message += `${'='.repeat(30)}\n\n`;
message += `Total DB Size: ${data.totalSizeGB} GB\n`;
message += `Tables Monitored: ${data.tableCount}\n`;
message += `Slow Queries: ${data.slowQueryCount}\n\n`;

for (const issue of data.issues) {
  const icon = issue.severity === 'critical' ? 'CRITICAL' : issue.severity === 'warning' ? 'WARNING' : 'INFO';
  message += `[${icon}] ${issue.type}\n`;
  for (const d of issue.details) {
    message += `  - ${d}\n`;
  }
  message += `\n`;
}

message += `Top Tables:\n`;
for (const t of data.tables) {
  message += `  ${t.name}: ${t.size} (${Number(t.rows).toLocaleString()} rows)\n`;
}

return [{ json: { message, chatId: process.env.TELEGRAM_ALERT_CHAT_ID || '' } }];
